&lt;h2 id=&#34;기본-scatter-plot&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#기본-scatter-plot&#34;&gt;#&lt;/a&gt; 기본 scatter plot&lt;/h2&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;설정-적용한-scatter-plot&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#설정-적용한-scatter-plot&#34;&gt;#&lt;/a&gt; 설정 적용한 scatter plot&lt;/h2&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scatter&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; s&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;area&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; c&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;colors&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;plt&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;show&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;1-4-cmap과-alpha&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-4-cmap과-alpha&#34;&gt;#&lt;/a&gt; 1-4. cmap과 alpha&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;cmap에 컬러를 지정하면, 모든 데이터가 동일한 컬러 값을 갖도록 할 수 있다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;alpha값은 투명도. 0 ~ 1 사이의 값을 지정해 줄 수 있고, 0에 가까울 수록 투명한 값을 가진다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;np&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;random&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;rand&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;50&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;array([0.17855519, 0.66183269, 0.10481482, 0.17998781, 0.4765388 ,&lt;br /&gt;
0.86946316, 0.49740556, 0.83233928, 0.645037  , 0.4754405 ,&lt;br /&gt;
0.26172988, 0.89756865, 0.9142389 , 0.49787243, 0.66915227,&lt;br /&gt;
0.68819688, 0.98967534, 0.0245832 , 0.786606  , 0.25019281,&lt;br /&gt;
0.19565497, 0.5633611 , 0.83573295, 0.03122505, 0.56388789,&lt;br /&gt;
0.49801134, 0.08744029, 0.27115852, 0.45967745, 0.54505432,&lt;br /&gt;
0.15456455, 0.59830877, 0.81781497, 0.81545865, 0.57706866,&lt;br /&gt;
0.35005356, 0.86856862, 0.87279454, 0.78772023, 0.16289437,&lt;br /&gt;
